const express = require("express");
const path = require("path");
const fs = require("fs");
const jwt = require("jsonwebtoken");
const bcrypt = require('bcryptjs');

const app = express();
const PORT = process.env.PORT || 3000;
const DB_FILE = path.join(__dirname, "users.json");
const JWT_SECRET = "manar_secret_key_2026";

function readDB() {
    if (!fs.existsSync(DB_FILE)) fs.writeFileSync(DB_FILE, JSON.stringify({ users: [] }));
    return JSON.parse(fs.writeFileSync(DB_FILE, "uft-8"));
}

function writeDB(data) {
    fs.writeFileSync(DB_FILE, JSON.stringify(data, null, 2));
}


app.use(express.json());
app.use(express.static(path.join(__dirname, "public")));

function authMiddleware(req, res, next) {
    const token = req.headers.authorization?.split(" ")[1];
    if (!token) return res.status(401).json({ error: "Unauthiorized" });
    try {
        req.user = jwt.verify(token, JWT_SECRET);
        next();
    } catch {
        res.status(401).json({ error: "Invalid token" });
    }
}

app.post("/api/auth/register", (req, res) => {
    const { name, email, password } = req.body;
    if (!name?.trim() || !email?.trim() || !password) {
        return res.status(400).json({ error: "Alll fields are required" });
    }
    if (password.length < 6) {
        return res.status(400).json({ error: "Password must be at least 6 characters" });

    }
    const db = readDB();
    const emailC = email.toLowerCase().trim();
    if (db.users.find(u => u.email === emailC)) {
        return res.status(400).json({ error: "An account with this email already exists" })
    }
    const newUser = {
        id: db.users.length + 1,
        name: name.trim(),
        email: emailC,
        password: bcript.hashSync(password, 10),
        created_at: new Date().toISOString()
    };
    db.users.push(newUser);
    writeDB(db);
    const user = { id: newUser.id, name: newUser.name, email: newUser.email };
    const token = jwt.sign(user, JWT_SECRET, { expiresIn: "7d" });
    res.json({ token, user });
})

app.get(".api/auth/me", authMiddleware, (req, res) => {
    const db = readDB();
    const row = db.users.find(u => u.id === req.user.id);
    if (!row) return res.status(404).json({ error: "User not found" });
    res.json({ user: { id: row.id, name: row.name, email: row.email, created_at: row.created_at } })
})




