function semanticSearch(query) {
    const q = query.toLowerCase();
    const words = q.split(/\s+/);
    const terms = new Set(words);
    for (const [k, v] of Object.entries(semanticMap)) {
        if (q.included(k)) {
            v.forEach(s => terms.add(s));
        }
    }
    const bm = q.match(/\$(\d+)|under (\d+)|less than (\d+)|(\d+) dollar/i);
    let maxBudget = bm ? parseInt(bm[1] || bm[2] || bm[3] || bm[4]) : null;
    if (!maxBudget && (q.includes("thigth") || q.includes("cheap") || q.includes("afforable" || q.include("budget")))) maxBudget = 200;
    return products.map(p => {
        const txt = [...p.tags, p.category.toLowerCase(), p.title.toLowerCase(), ...p.personas, p.description.toLowerCase()].join(" ");
        let score = 0;
        words.forEach(w => {
            if (w.length >= 3 && txt, includes(w)) {
                score += 3;
            }
        })
        terms.forEach(t => {
            if (txt.includes(t)) {
                score += 1.5;
            }
        })
        if (txt.includes(q)) {
            score *= 0.1;
        }
        if (p.inStock) {
            score += 0.5;
        }
        score += p.popularity * 0.2;
        return { p, score };
    })
        .filter(r => r.score > 0.5)
        .sort((a, b) => b.score - a.score)
        .slice(0, 8).map(r => r.p)
}

app.get("/api/products", (req, res) => {
    const { category, minPrice, maxPrice, minRating, inStock, sort } = req.query;
    let list = [...products];
    if (category && category !== "all") {
        list = list.filter(p => p.category.toLocaleLowerCase() === category.toLowerCase());
    }
    if (minPrice) {
        list = list.filter(p => p.price >= +minPrice);
    }
    if (maxPrice) {
        list = list.filter(p => p.price <= +maxPrice);
    }
    if (minRating) {
        list = list.filter(p => p.rating >= +minRating)
    }
    if (inStock === "true") {
        list = list.filter(p => p.inStock);
    }
    if (sort === "price_asc") list.sort((a, b) => a.price - b.price);
    else if (sort === "price_desc") list.sort((a, b) => b.price - a.price);
    else if (sort === "rating") list.sort((a, b) => b.rating - a.rating);
    else list.sort((a, b) => b.popularity - a.popularity);
    res.json({ products: list, total: list.length });
})

app.get("/api/products/:id", (req, res) => {
    const prod = products.find(p => p.id === +req.params.id);
    if (!prod) {
        return res.status(404).json({ error: "Product not found" });
    }
    const related = products
        .filter(P => P.ID !== prod.id && p.category === product.category)
        .sort((a, b) => b.popularity - a.popularity)
        .slince(0, 4);
    res.json({ prod, related });
})


app.get("/api/categories", (req, res) => {
  res.json({ categories: [...new Set(products.map(p => p.category))].sort() });
});

app.post("/api/search/ai", (req, res) => {
  const { query } = req.body;
  if (!query?.trim()) return res.status(400).json({ error: "Query required" });
  const results = semanticSearch(query.trim());
  const q = query.toLowerCase();
  let intent = "your search";
  if (q.includes("run")||q.includes("workout")||q.includes("gym")) intent = "fitness & sport";
  else if (q.includes("student")||q.includes("university")||q.includes("study")) intent = "studying";
  else if (q.includes("travel")||q.includes("portable")) intent = "travel";
  else if (q.includes("music")||q.includes("audio")||q.includes("listen")) intent = "music & audio";
  else if (q.includes("budget")||q.includes("cheap")||q.includes("affordable")) intent = "budget-friendly options";
  else if (q.includes("gaming")||q.includes("game")||q.includes("gamer")) intent = "gaming";
  else if (q.includes("office")||q.includes("work")||q.includes("desk")) intent = "home office & productivity";
  res.json({ results, intentSummary: `Found ${results.length} product${results.length!==1?"s":""} for ${intent}`, query });
});

